"""Exact normalized snapshots for representative existing structural outputs."""
import json
import unittest

from renegade import inspect_grid
from renegade.characterize import normalized_snapshot


class NormalizedSnapshotTests(unittest.TestCase):
    def test_representative_snapshots_are_exact_and_runtime_free(self):
        cases = {
            "empty": ((0,),), "single": ((1,),), "filled": ((1, 1), (1, 1)),
            "hollow": ((1, 1, 1), (1, 0, 1), (1, 1, 1)),
            "checkerboard": ((1, 0), (0, 1)), "translation": ((1, 0, 1),),
        }
        snapshots = {name: normalized_snapshot(inspect_grid(grid, name)) for name, grid in cases.items()}
        encoded = json.dumps(snapshots, sort_keys=True, separators=(",", ":"), default=list)
        self.assertEqual(encoded, EXPECTED_SNAPSHOT_JSON)


